SELECT
sct.*,
ssc.id AS collection_id,
send_email_count
FROM
store_celebrity_trial sct FORCE INDEX ( id )
LEFT JOIN store_seller_collection ssc ON ssc.celebrity_id=sct.id

    AND ssc.seller_id = #{storeCelebrityTrialModel.sellerId}

LEFT JOIN ( SELECT kol_email, COUNT( id ) AS send_email_count FROM store_message_push_detail WHERE seller_id =
#{storeCelebrityTrialModel.sellerId} and is_send!=-2 GROUP BY kol_email ) smp ON smp.kol_email = sct.email
where 1=1

    AND sct.platform_type = #{storeCelebrityTrialModel.platformType}


    AND sct.star = #{storeCelebrityTrialModel.star}


    and sct.followers_num >= #{storeCelebrityTrialModel.followersStartNum}


    and sct.followers_num <= #{storeCelebrityTrialModel.followersEndNum}


    and sct.play_avg_num >= #{storeCelebrityTrialModel.playAvgStartNum}


    and sct.play_avg_num <= #{storeCelebrityTrialModel.playAvgEndNum}


    and sct.posts_num >= #{storeCelebrityTrialModel.postsStartNum}


    and sct.posts_num <= #{storeCelebrityTrialModel.postsEndNum}


    AND sct.country = #{storeCelebrityTrialModel.country}


    AND sct.nick_name like '%${storeCelebrityTrialModel.nickName}%'



        AND find_in_set('${item}',like_tags)



    AND sct.gender = #{storeCelebrityTrialModel.gender}

ORDER BY
sct.create_time DESC

SELECT
count(1) as count
FROM
store_celebrity_trial sct FORCE INDEX ( id )
LEFT JOIN store_seller_collection ssc ON ssc.celebrity_id=sct.id

    AND ssc.seller_id = #{storeCelebrityTrialModel.sellerId}

LEFT JOIN ( SELECT kol_email, COUNT( id ) AS send_email_count FROM store_message_push_detail WHERE seller_id =
#{storeCelebrityTrialModel.sellerId} and is_send!=-2 GROUP BY kol_email ) smp ON smp.kol_email = sct.email
where 1=1

    AND sct.platform_type = '${storeCelebrityTrialModel.platformType}'


    AND sct.star = '${storeCelebrityTrialModel.star}'


    and sct.followers_num >= #{storeCelebrityTrialModel.followersStartNum}


    and sct.followers_num <= #{storeCelebrityTrialModel.followersEndNum}


    and sct.play_avg_num >= #{storeCelebrityTrialModel.playAvgStartNum}


    and sct.play_avg_num <= #{storeCelebrityTrialModel.playAvgEndNum}


    and sct.posts_num >= #{storeCelebrityTrialModel.postsStartNum}


    and sct.posts_num <= #{storeCelebrityTrialModel.postsEndNum}


    AND sct.country = '${storeCelebrityTrialModel.country}'


    AND sct.nick_name like '%${storeCelebrityTrialModel.nickName}%'



        AND find_in_set('${item}',like_tags)



    AND sct.gender = #{storeCelebrityTrialModel.gender}
